@file:Suppress("UnusedVariable", "unused")

package dev.sargunv.mobilitydata.gbfs.v1

import kotlinx.coroutines.test.runTest

class DocsSnippet {
  fun example() = runTest {
    // --8<-- [start:example]
    GbfsV1Client().use { gbfs -> // (1)!
      val manifest =
        gbfs
          .getSystemManifest.await( // (2)!
            discoveryUrl = "https://data.lime.bike/api/partners/v1/gbfs/seattle/gbfs.json"
          )
          .data

      context(manifest.getService("en")) { // (3)!
        val systemInfo = gbfs.getSystemInformation().await().data // (4)!

        println("System: ${systemInfo.name}")
        println("Operator: ${systemInfo.operator}")
        println("Timezone: ${systemInfo.timezone}")

        val stations = gbfs.getStationInformation().await().data // (5)!

        println("\nStations: ${stations.size}")
        stations.take(3).forEach { station ->
          println("  - ${station.name} (${station.capacity} bikes)")
        }

        val freeBikes = gbfs.getFreeBikeStatus().await().data.bikes // (6)!

        println("\nAvailable bikes: ${freeBikes.size}")
        freeBikes.take(3).forEach { bike ->
          println("  - ${bike.bikeId} at (${bike.lat}, ${bike.lon})")
        }
      }
    }
    // --8<-- [end:example]
  }
}

package dev.sargunv.mobilitydata.gbfs.v1

import io.ktor.client.engine.mock.MockEngine
import io.ktor.client.engine.mock.respond
import io.ktor.client.engine.mock.respondError
import io.ktor.http.HttpStatusCode
import io.ktor.http.fullPath
import io.ktor.http.headersOf
import kotlin.test.Test
import kotlin.test.assertTrue
import kotlinx.coroutines.test.runTest
import kotlinx.io.buffered
import kotlinx.io.files.FileNotFoundException
import kotlinx.io.files.Path
import kotlinx.io.files.SystemFileSystem
import kotlinx.io.readString

class ProducerTest {
  private fun createMockEngine(resourcesSubdirectory: String): MockEngine {
    val cwd = SystemFileSystem.resolve(Path("."))
    val projectDir =
      when (cwd.name) {
        "mobility-data-gbfs-v1-test" -> cwd.parent!!.parent!!.parent!!.parent!!
        "gbfs-v1" -> cwd.parent!!
        else -> error("unexpected: $cwd")
      }
    return MockEngine { request ->
      val fileName = Path(request.url.fullPath).name
      val suffix = if (fileName.endsWith(".json")) "" else ".json"
      val localPath =
        Path("$projectDir", "sample-data", "gbfs-v1", resourcesSubdirectory, fileName + suffix)
      try {
        val source = SystemFileSystem.source(localPath)
        val content = source.buffered().readString()
        respond(content, HttpStatusCode.OK, headersOf("Content-Type" to listOf("application/json")))
      } catch (_: FileNotFoundException) {
        respondError(HttpStatusCode.NotFound)
      }
    }
  }

  @Test
  fun publicbikesystem() = runTest {
    val client = GbfsV1Client(createMockEngine("publicbikesystem"))

    val manifest = client.getSystemManifest("gbfs").getOrThrow()
    val service = manifest.data.getService("en")

    context(service) {
      assertTrue(client.getSystemInformation().isSuccess)
      assertTrue(client.getSystemPricingPlans().isSuccess)
      assertTrue(client.getStationInformation().isSuccess)
      assertTrue(client.getStationStatus().isSuccess)
      assertTrue(client.getSystemRegions().isSuccess)
    }
  }

  @Test
  fun bird() = runTest {
    val client = GbfsV1Client(createMockEngine("bird"))
    val manifest = client.getSystemManifest("gbfs.json").getOrThrow()
    val service = manifest.data.getService("en")

    context(service) {
      assertTrue(client.getSystemInformation().isSuccess)
      assertTrue(client.getVersionManifest().isSuccess)
      assertTrue(client.getSystemRegions().isSuccess)
      assertTrue(client.getFreeBikeStatus().isSuccess)
    }
  }

  @Test
  fun bcycle() = runTest {
    val client = GbfsV1Client(createMockEngine("bcycle"))

    val manifest = client.getSystemManifest("gbfs.json").getOrThrow()
    val service = manifest.data.getService("en")

    context(service) {
      assertTrue(client.getSystemInformation().isSuccess)
      assertTrue(client.getStationInformation().isSuccess)
      assertTrue(client.getStationStatus().isSuccess)
      assertTrue(client.getSystemRegions().isSuccess)

      // INVALID: data is empty {}
      // client.getVersionManifest()

      // INVALID: description is missing
      // client.getSystemPricingPlans()
    }
  }

  @Test
  fun donkey() = runTest {
    val client = GbfsV1Client(createMockEngine("donkey"))

    val manifest = client.getSystemManifest("gbfs.json").getOrThrow()
    val service = manifest.data.getService("en")

    context(service) {
      assertTrue(client.getSystemInformation().isSuccess)
      assertTrue(client.getStationInformation().isSuccess)
      assertTrue(client.getStationStatus().isSuccess)
      assertTrue(client.getSystemHours().isSuccess)
      assertTrue(client.getSystemRegions().isSuccess)
      assertTrue(client.getSystemPricingPlans().isSuccess)
    }
  }

  @Test
  fun bolt() = runTest {
    val client = GbfsV1Client(createMockEngine("bolt"))

    val manifest = client.getSystemManifest("gbfs").getOrThrow()
    val service = manifest.data.getService("en")

    context(service) {
      assertTrue(client.getSystemInformation().isSuccess)
      assertTrue(client.getFreeBikeStatus().isSuccess)
      assertTrue(client.getSystemPricingPlans().isSuccess)
    }
  }

  @Test
  fun lime() = runTest {
    val client = GbfsV1Client(createMockEngine("lime"))

    val manifest = client.getSystemManifest("gbfs").getOrThrow()
    val service = manifest.data.getService("en")

    context(service) {
      assertTrue(client.getSystemInformation().isSuccess)
      assertTrue(client.getFreeBikeStatus().isSuccess)
      assertTrue(client.getStationInformation().isSuccess)

      // INVALID: num_bikes_available is named num_vehicles_available
      // client.getStationStatus()
    }
  }
}

